/**
 * 产品卡片组件
 * @author <smallletters@sina.com>
 * @date 2026-03-27
 * @description 可复用的产品卡片，显示产品图片、名称、价格和折扣标签
 */

import { motion } from "framer-motion";

interface ProductCardProps {
  id: string;
  name: string;
  price: number;
  originalPrice?: number;
  image: string;
  discount?: string;
  isNew?: boolean;
  link: string;
  index?: number;
}

export default function ProductCard({
  name,
  price,
  originalPrice,
  image,
  discount,
  isNew,
  link,
  index = 0,
}: ProductCardProps) {
  return (
    <motion.a
      href={link}
      target="_blank"
      rel="noopener noreferrer"
      initial={{ opacity: 0, y: 20 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{ duration: 0.4, delay: index * 0.05 }}
      className="group block bg-white rounded-lg overflow-hidden hover:shadow-xl transition-shadow duration-300"
    >
      {/* 图片容器 - 居中对齐 */}
      <div className="relative h-48 sm:h-56 overflow-hidden bg-gray-50">
        {/* eslint-disable-next-line @next/next/no-img-element */}
        <img
          src={image}
          alt={name}
          className="absolute inset-0 w-full h-full object-contain object-center p-6 group-hover:scale-105 transition-transform duration-500"
          loading="lazy"
        />
        
        {/* 折扣标签 */}
        {discount && (
          <span className="absolute top-2 left-2 bg-[#e53935] text-white text-xs font-bold px-2 py-1 rounded">
            {discount}
          </span>
        )}
        
        {/* 新品标签 */}
        {isNew && !discount && (
          <span className="absolute top-2 left-2 bg-[#4caf50] text-white text-xs font-bold px-2 py-1 rounded">
            New
          </span>
        )}
      </div>

      {/* 产品信息 */}
      <div className="p-4">
        <h3 className="text-sm font-medium text-gray-800 line-clamp-2 mb-2 group-hover:text-[#e53935] transition-colors">
          {name}
        </h3>
        <div className="flex items-center gap-2">
          <span className="text-lg font-bold text-[#e53935]">
            ${price.toFixed(2)}
          </span>
          {originalPrice && (
            <span className="text-sm text-gray-400 line-through">
              ${originalPrice.toFixed(2)}
            </span>
          )}
        </div>
      </div>
    </motion.a>
  );
}
