/**
 * 导航栏组件
 * @author <smallletters@sina.com>
 * @date 2026-03-27
 * @description 网站顶部导航，包含Logo、菜单、搜索和购物车
 */

"use client";

import { useState } from "react";
import { Search, ShoppingCart, User, Menu, X, ChevronDown } from "lucide-react";

const navItems = [
  { name: "NEW ARRIVALS", href: "#new-arrivals" },
  { name: "BEST SELLERS", href: "#best-sellers" },
  { name: "DEVICES", href: "#", hasDropdown: true },
  { name: "E-LIQUID", href: "#", hasDropdown: true },
  { name: "ACCESSORIES", href: "#", hasDropdown: true },
  { name: "BLOG", href: "#blog" },
];

export default function Header() {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);

  return (
    <header className="w-full bg-white border-b border-gray-200 sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          {/* Mobile Menu Button */}
          <button
            className="lg:hidden p-2 text-gray-700 hover:text-black transition-colors"
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            aria-label="Toggle menu"
          >
            {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>

          {/* Logo */}
          <a href="/" className="flex-shrink-0">
            <h1 className="text-2xl font-bold tracking-tight text-[#1a1a1a]">
              EVERZON
            </h1>
          </a>

          {/* Desktop Navigation */}
          <nav className="hidden lg:flex items-center space-x-8">
            {navItems.map((item) => (
              <a
                key={item.name}
                href={item.href}
                className="flex items-center text-sm font-medium text-gray-700 hover:text-black transition-colors"
              >
                {item.name}
                {item.hasDropdown && <ChevronDown size={14} className="ml-1" />}
              </a>
            ))}
          </nav>

          {/* Right Actions */}
          <div className="flex items-center space-x-4">
            {/* Search */}
            <button
              className="p-2 text-gray-700 hover:text-black transition-colors"
              onClick={() => setIsSearchOpen(!isSearchOpen)}
              aria-label="Search"
            >
              <Search size={20} />
            </button>

            {/* User */}
            <button
              className="hidden sm:block p-2 text-gray-700 hover:text-black transition-colors"
              aria-label="Account"
            >
              <User size={20} />
            </button>

            {/* Cart */}
            <button
              className="p-2 text-gray-700 hover:text-black transition-colors relative"
              aria-label="Cart"
            >
              <ShoppingCart size={20} />
              <span className="absolute -top-1 -right-1 bg-[#e53935] text-white text-xs rounded-full w-4 h-4 flex items-center justify-center">
                0
              </span>
            </button>
          </div>
        </div>

        {/* Search Bar */}
        {isSearchOpen && (
          <div className="py-4 border-t border-gray-100 animate-fade-in">
            <div className="relative">
              <input
                type="text"
                placeholder="Search for products..."
                className="w-full px-4 py-3 pl-12 border border-gray-300 rounded-lg focus:outline-none focus:border-black transition-colors"
              />
              <Search
                size={20}
                className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"
              />
            </div>
          </div>
        )}
      </div>

      {/* Mobile Menu */}
      {isMobileMenuOpen && (
        <div className="lg:hidden border-t border-gray-200 bg-white animate-slide-up">
          <nav className="px-4 py-4 space-y-2">
            {navItems.map((item) => (
              <a
                key={item.name}
                href={item.href}
                className="flex items-center justify-between py-3 text-sm font-medium text-gray-700 hover:text-black border-b border-gray-100"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                {item.name}
                {item.hasDropdown && <ChevronDown size={16} />}
              </a>
            ))}
            <a
              href="#"
              className="flex items-center py-3 text-sm font-medium text-gray-700 hover:text-black"
            >
              <User size={18} className="mr-3" />
              My Account
            </a>
          </nav>
        </div>
      )}
    </header>
  );
}
